        "principles": {
          "kicker": "F · Principles",
          "title": "Seven cross-cutting <em>design principles</em>",
          "caption": "Not local UX tweaks — system-wide constraints that hold across performance / inventory / promotion, and stay valid as the business expands.",
          "items": [
            {
              "num": "01",
              "head": "Reorganise information around \"people\" and \"org\"",
              "body": "Not around forms and modules. Whichever flow they enter, the same person / org always presents the same unified view."
            },
            {
              "num": "02",
              "head": "Raise signal-to-noise — don't show more",
              "body": "Shift the design goal from \"complete the field set\" to \"surface what matters\" — distribution, risk flags, history, rater bias."
            },
            {
              "num": "03",
              "head": "Progressive disclosure · the critical task first",
              "body": "Main table scans group-level outliers / profile absorbs detail lookup / hover provides light, incremental info."
            },
            {
              "num": "04",
              "head": "Consistent feedback language",
              "body": "What does this filter affect, what does the current state mean, what comes next — every scenario speaks the same feedback grammar."
            },
            {
              "num": "05",
              "head": "Outliers first · sort by decision relevance",
              "body": "Pull \"differences that need attention\" from the middle of the table to the top — let managers see risk on first glance."
            },
            {
              "num": "06",
              "head": "From individual scoring → organisational calibration",
              "body": "Calibration isn't a result view — it's the organisation aligning definitions and surfacing bias. Modelled as its own workflow node."
            },
            {
              "num": "07",
              "head": "Design for sustainable evolution",
              "body": "The same hierarchy · state · feedback rules carry across performance / inventory / promotion — no need to redesign from scratch when business expands."
            }
          ]
        }
